{
  "scripts": {
    "dev":       "vite",
    "build":     "tsc && vite build",
    "preview":   "vite preview",
    "test":      "vitest",
    "lint":      "eslint src",
    "typecheck": "tsc --noEmit",
    "ci":        "npm run typecheck && npm run lint && npm run test"
  }
}

{
  "dependencies": {
    "react": "^18.3.1",   // >= 18.3.1 < 19.0.0  (caret: compatible)
    "lodash": "~4.17.21", // >= 4.17.21 < 4.18.0  (tilde: patch only)
    "dayjs": "1.11.10",   // exactly 1.11.10
    "zod": ">=3.22.0",    // any version >=3.22.0
    "axios": "*"          // any version (avoid in production)
  }
}

// npm 8.3+ syntax:
{
  "overrides": {
    "some-package": "1.2.3"
  }
}

// yarn syntax:
{
  "resolutions": {
    "some-package": "1.2.3"
  }
}

// pnpm syntax:
{
  "pnpm": {
    "overrides": {
      "some-package": "1.2.3"
    }
  }
}

{
  "name": "my-react-app",
  "private": true,           // never publish to npm
  "version": "0.0.0",       // no semantics for apps
  "type": "module",         // ESM throughout
  "scripts": {
    "dev":     "vite",              // start dev server
    "build":   "tsc && vite build", // type-check, then bundle
    "preview": "vite preview",      // preview the built output
    "test":    "vitest"
  },
  "dependencies": {
    "react":     "^18.3.1",  // ships to users
    "react-dom": "^18.3.1"
  },
  "devDependencies": {
    "@types/react":          "^18.3.3",  // TS types only
    "@types/react-dom":      "^18.3.0",
    "@vitejs/plugin-react":  "^4.3.1",   // Vite React plugin
    "typescript":            "^5.5.3",   // transpile TS
    "vite":                  "^5.4.1"    // bundler/dev-server
  }
}

{
  "browserslist": [
    ">0.2%",
    "not dead",
    "not op_mini all"
  ]
}

// Or environment-specific:
{
  "browserslist": {
    "production": [">0.2%", "not dead", "not op_mini all"],
    "development": ["last 1 chrome version", "last 1 firefox version"]
  }
}

{
  "name": "my-ui-lib",
  "version": "1.0.0",
  "type": "module",
  "exports": {
    ".": {
      "import": "./dist/index.mjs",    // ESM (Vite, bundlers)
      "require": "./dist/index.cjs",   // CommonJS (Jest, old tools)
      "types": "./dist/index.d.ts"     // TypeScript types
    },
    "./Button": {
      "import": "./dist/Button.mjs",
      "types": "./dist/Button.d.ts"
    }
  },
  "peerDependencies": {
    "react": "^17.0.0 || ^18.0.0"
  },
  "sideEffects": false
}

# Public scoped packages on npm registry:
@types/react           # TypeScript types for React
@vitejs/plugin-react   # Vite plugin by Vite team
@tanstack/react-query  # TanStack organisation

# Install scoped package:
npm install @types/react

# Install from a private GitHub registry for @myorg scope:
# First, configure in .npmrc:
# @myorg:registry=https://npm.pkg.github.com
npm install @myorg/design-system
